INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", 0.0, 24, "訓練成功、おめでとうございます\n褒めるべき時にはしっかり褒めるのも\n教官の務めですものね。それとも、\n罵られる方が好みですか？　クスクス", 10142, "2030/12/17 14:59:59", 100, 7, 100, 129901, 1, 10.85, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", 0.0, 24, "厳しい訓練も、終わってみれば\n短く感じるものですわね。\n正直、私は暴れ足りないくらい…\nいえ、何でもありませんわ。クスクス", 10142, "2030/12/17 14:59:59", 101, 2, 101, 129901, 1, 11.15, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", 0.0, 24, "行く手を阻む忌々しい邪魔者を\n蹴散らして、見事ゴールイン…！\nまるで私とあのおかたの人生を\n象徴するような道のりでした…", 10142, "2030/12/17 14:59:59", 102, 5, 102, 129901, 7, 6.4, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", 0.0, 24, "まったくもって不甲斐ない結果です\nしかし、挽回の機会はまだありますわ\n次はゴミ虫の地位から脱却できるよう\n死力を尽くしなさい。いいですね？", 10142, "2030/12/17 14:59:59", 103, 3, 103, 129901, 3, 0.0, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", 0.0, 24, "クスクス…ああご心配なさらず\nなんとも情けない成績を残す輩には\nどんな罰が相応しいか、考えている\nだけですので…クスクスクス", 10142, "2030/12/17 14:59:59", 104, 8, 104, 129901, 2, 2.43, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", 0.0, 24, "私が教官として認められなければ、\nあのおかたを失望させてしまう…\nそれだけはあってはなりません\nあなた方も、わかっていますわね？", 10142, "2030/12/17 14:59:59", 105, 3, 105, 129901, 4, 9.08, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", 0.0, 24, "まずまずの結果ではありますが、\nこの程度で満足してもらっては\n困りますわ。エリコ班の一員として、\nより高みを目指していただきますので", 10142, "2030/12/17 14:59:59", 106, 6, 106, 129901, 6, 0.0, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", 0.0, 24, "私の指導を受けながら、この結果は…\nもっと真剣に考えねばなりませんね\nあなた方が怠けずにいるには、\nどんなしつけが必要かを…クスクス", 10142, "2030/12/17 14:59:59", 107, 8, 107, 129901, 3, 10.6, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", 0.0, 24, "ひとまず訓練をこなしたご褒美か、\n実力を出しきれたとは言えない罰か…\nみなさんにどちらを与えるべきか\n少し悩む結果ですわね", 10142, "2030/12/17 14:59:59", 108, 4, 108, 129901, 6, 7.54, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", 0.0, 24, "なかなかいい戦いぶりでしたわ\nこれもあなた方の頑張りと、何より\n優秀な教官である私の教育の賜物\nそうですわね？　クスクスクス…", 10142, "2030/12/17 14:59:59", 109, 7, 109, 129901, 2, 11.5, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", 0.0, 24, "これだけ進めたのならば合格点ですわ\nでも、もっと高みを目指したいと\n思っているのなら…さらなる訓練にも\n付き合って差し上げましょう", 10142, "2030/12/17 14:59:59", 110, 1, 110, 129901, 2, 8.83, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", 0.0, 24, "未熟で頼りなかったあなた方が、\n見違えるように成長しました\nなるほど…これこそが、教官冥利に\n尽きるという気持ちなのですね", 10142, "2030/12/17 14:59:59", 111, 2, 111, 129901, 1, 6.68, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", 0.0, 24, "まさかあなた方が、私の予想すら\n超える力を発揮するとは…驚きました\nもはやゴミ虫などではありません\n一人前の騎士として胸を張りなさい", 10142, "2030/12/17 14:59:59", 112, 2, 112, 129901, 6, 8.8, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", 0.0, 24, "クスクス、見事な働きです\nみなさんならできると信じていました\n他でもない私の指導を受けた、\nエリコ班の優秀な新兵なのですから", 10142, "2030/12/17 14:59:59", 113, 1, 113, 129901, 2, 8.9, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("エリコ", 0.0, 24, "なんてすばらしい成績…！\n今日という日は『あのおかたを想い\nエリコが限界を超えた記念日』として\n歴史に刻まれることでしょう…！", 10142, "2030/12/17 14:59:59", 114, 5, 114, 129901, 2, 3.7, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", 0.0, 24, "よし、いい訓練になったな\nおまえたちもよく動けてたし、\nちゃんと成長できてると思うぜ\nその調子で頑張れよっ", 10142, "2030/12/17 14:59:59", 200, 2, 200, 129801, 1, 7.6, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", 0.0, 24, "ひとまずゴールおめでとう！\nでも、努力は継続してこそだからな\nおまえたちにやる気があるなら、\n何度だって付き合ってやるよ", 10142, "2030/12/17 14:59:59", 201, 1, 201, 129801, 2, 2.25, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", 0.0, 24, "行軍訓練はこれにて完了！\n…なーんて思ってないよな？\n学んだことが体に染みつくまで\n地道に繰り返すのが練習ってもんさ", 10142, "2030/12/17 14:59:59", 202, 1, 202, 129801, 2, 3.28, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", 0.0, 24, "みんなに無理をさせちまったか…\nでもこれで諦めることはないぜ\n次はきっとうまくいく。そう信じて\n鍛え続ければ、道は開けるはずだ！", 10142, "2030/12/17 14:59:59", 203, 1, 203, 129801, 4, 2.98, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", 0.0, 24, "こいつは悔しい結果だな…\nま、反省点はいろいろあったし\nひとつずつ乗り越えていこう\nあたしたちで力を合わせて、なっ！", 10142, "2030/12/17 14:59:59", 204, 1, 204, 129801, 4, 3.0, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", 0.0, 24, "おまえたちはまだ未熟な訓練兵、\n失敗を必要以上に悔やむことはねえよ\nでも実戦じゃこうはいかないからな\n次は気合を入れ直していけよっ！", 10142, "2030/12/17 14:59:59", 205, 2, 205, 129801, 1, 10.3, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", 0.0, 24, "これがおまえたちの全力？\nいやいや、そんなはずはないよなっ\nおまえらならもっと強くなれる！\nあたしが言うんだ、間違いないぜ！", 10142, "2030/12/17 14:59:59", 206, 1, 206, 129801, 6, 2.93, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", 0.0, 24, "おまえたちの実力を考えりゃ、\nベストを尽くせたとは言えない成績だ\nなら、次やるべきことも決まってる\n気持ちを切り替えて、鍛え直すんだ！", 10142, "2030/12/17 14:59:59", 207, 1, 207, 129801, 3, 9.3, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", 0.0, 24, "まだまだ課題がある内容だったな～\n無駄な動き、判断の遅れ…\nそういうのをしっかり直していけば、\n記録ももっと伸びるはずだっ", 10142, "2030/12/17 14:59:59", 208, 1, 208, 129801, 4, 6.9, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", 0.0, 24, "ここまでいけりゃ、合格点！\nむしろ、最初の頼りなさを思えば\nすげえ成長してるんじゃねえか？\n胸を張れる結果だと思うぜっ！", 10142, "2030/12/17 14:59:59", 209, 2, 209, 129801, 2, 0.0, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", 0.0, 24, "なかなかハードな訓練だったけど、\nみんなしっかりついてこられたな\n地道に続けた基礎トレの成果が\n形になってる、その証だぜっ", 10142, "2030/12/17 14:59:59", 210, 2, 210, 129801, 1, 5.95, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", 0.0, 24, "今回の訓練もよく頑張ったな！\nしっかり休んで次に備えろよ！\nなんつーか、教え子が成長してくのを\n見るのは楽しいもんだな…", 10142, "2030/12/17 14:59:59", 211, 1, 211, 129801, 2, 6.73, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", 0.0, 24, "おまえら、すげえじゃねえか！\nこれならもう、ひよっこ新兵なんて\n言えねえな。きっと騎士団でも\n大活躍間違いなしだぜ！", 10142, "2030/12/17 14:59:59", 212, 2, 212, 129801, 2, 0.0, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", 0.0, 24, "敵との戦い方、状況判断の正確さ\n何より根性…どれも最高だったぞ！\nうかうかしてたら、教官のあたしまで\n追い抜かれちまうかもな…へへっ", 10142, "2030/12/17 14:59:59", 213, 2, 213, 129801, 1, 6.65, "2024/03/31 12:00:00", 0.0);
INSERT INTO `v1_f85a2b4ee3d11ebf86d8854078ed39b8f6ec2eca8a1e9b3167665b76f3608fac` VALUES ("マコト", 0.0, 24, "あたしの指導が良かった？\nいやいや、ここまで強くなれたのは、\n他でもないおまえたち自身が努力した\nおかげだよ。改めて…おめでとうっ！", 10142, "2030/12/17 14:59:59", 214, 1, 214, 129801, 6, 3.05, "2024/03/31 12:00:00", 0.0);
